const body = $input.first().json.body || $input.first().json;

const contactId = body.contact_id || body.contactId || '';
const phone = body.phone || body.phoneNumber || '';
const nombre = body.full_name || body.first_name || body.name || 'Lead';
const mensaje = body.message?.body || body.messageBody || '';
const conversationId = body.conversation_id || body.conversationId || '';
const locationId = body.location_id || 'YOUR_GHL_LOCATION_ID';
const direction = body.message?.direction || body.direction || 'inbound';
const messageType = body.message?.type || body.type || 'TYPE_TEXT';

// Solo mensajes entrantes de leads con contenido
if (direction !== 'inbound' || !contactId || !mensaje) {
  return [{ json: { skip: true, reason: `direction=${direction} contactId=${contactId} msg=${!!mensaje}` } }];
}

return [{
  json: {
    skip: false,
    contactId,
    phone,
    nombre,
    mensaje,
    conversationId,
    locationId,
    ghlLink: `https://app.gohighlevel.com/v2/location/${locationId}/conversations/${conversationId}`
  }
}];

const searchResult = $input.first().json;
const issues = Array.isArray(searchResult) ? searchResult : (searchResult.issues || searchResult.data || []);
const ghlData = $('Extraer Datos GHL').first().json;
const token = $('Login Paperclip').first().json.token;

// Buscar issue activa para este contactId (en el título)
const existing = issues.find(i =>
  i.title && i.title.includes(ghlData.contactId) &&
  !['done', 'cancelled'].includes(i.status)
);

return [{
  json: {
    ...ghlData,
    token,
    existingIssueId: existing?.id || null,
    isNew: !existing
  }
}];

